INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-01', 'Core domain: Study, Treatment, Stratum, CaseCell → SuccessRate falls out', 'complete', 'Studies, Treatments, Strata, CaseCells', 'For each (stratum, treatment) cell in a study, what is the success rate?', 'Kidney stone study (Charig 1986): 2 strata (small/large), 2 treatments (A/B), 4 cells. CellSuccessRate is the first derived fact.', 'Ask: for each treatment, what is its pooled (across all strata) success rate? That requires TreatmentSummary — aggregating CaseCells by treatment, ignoring stratum.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-02', 'TreatmentSummary: pooled rate per treatment across all strata', 'complete', 'TreatmentSummaries', 'If you ignore stratum entirely, what is each treatment''s overall success rate?', 'Pooled: A=273/350=78%, B=289/350=83%. B looks better — this is the misleading aggregate view.', 'Ask: for each (stratum, treatment) pair, what is the success rate WITHIN that stratum? That requires StratumSummary — the view that contradicts the pooled view.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-03', 'StratumSummary: per-stratum rate per treatment — the true picture', 'complete', 'StratumSummaries', 'Within each stratum, which treatment has the higher success rate?', 'Small: A=93.1% > B=86.7%. Large: A=73.0% > B=68.8%. A wins in BOTH strata. Contradiction with pooled view is now visible.', 'Ask: for each treatment pair in a study, does the pooled winner match the per-stratum winner? That requires TreatmentRanking — the node where the paradox either exists or doesn''t.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-04', 'TreatmentRanking: does the pooled winner = the per-stratum winner?', 'complete', 'TreatmentRankings', 'When pooled and stratified conclusions disagree — which treatment should actually be preferred?', 'Pooled winner = B. Per-stratum winner = A in every stratum. Simpson''s Paradox: IsReversal = true. This is the paradox as a derived fact, not a modeled entity.', 'Ask: WHY does the paradox occur? The stratifying variable (stone size) affects both treatment assignment AND outcome. Name it as a StratumVariable with a CausalRole field.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-05', 'StratumVariable: name the confounding factor, its causal role, and derive IsConfounder + IsParadoxExplained', 'complete', 'StratumVariables (one per study); CausalRole field; IsConfounder boolean; IsParadoxExplained on TreatmentRankings', 'What IS the stratum variable, why does it confound, and does the model witness its own explanation?', 'kidney-1986: VariableName=stone_size, CausalRole=confounder, AffectsTreatmentAssignment=true, AffectsOutcome=true → IsConfounder=true → IsParadoxExplained=true on TreatmentRankings.', 'Ask: how large is the allocation imbalance? Derive TreatmentExposureFraction on CaseCells — the fraction of each treatment''s cases that land in each stratum. High imbalance = confounding mechanism as a witnessed number.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-06', 'TreatmentExposureFraction: the allocation imbalance as a witnessed number', 'complete', 'TreatmentExposureFraction field on CaseCells (Cases / TotalCasesForTreatment in this study)', 'What fraction of each treatment''s total cases fall in each stratum? High imbalance across strata is the mechanism of confounding.', 'A: 263/350=75% in large-stone stratum. B: 80/350=23% in large-stone stratum. The 52-point gap IS the mechanism — now a first-class derived number.', 'Add a degenerate study where treatment allocation is perfectly balanced across strata. IsReversal must be FALSE — not because the data says so, but because the algebra guarantees it. The model witnesses its own structural impossibility.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-07', 'Degenerate study: balanced allocation → IsReversal structurally impossible', 'complete', 'Second Studies row (balanced-synthetic); equal TreatmentExposureFraction across strata; IsReversal = FALSE by construction', 'If every stratum gets the same treatment-allocation fraction, can a reversal occur? The DAG should witness that it cannot.', 'Synthetic: A and B each assigned 50/50 to small/large strata. A=60% success both strata, B=50% both. Pooled: A=60%, B=50%. No reversal. IsParadoxExplained vacuously true (IsConfounder=false, no confounding, no reversal).', 'Add Berkeley 1973 — same DAG, contested domain. Aggregate: women admitted at lower rate. Per-department: women admitted at equal or higher rate in most. IsReversal=true. But IsConfounder is ambiguous — department choice may be downstream of gender (mediator, not confounder). The model witnesses its own explanatory limits.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-08', 'Berkeley 1973: contested confounder — model reveals a PARTIAL paradox, not a clean reversal', 'complete', 'Third Studies row (berkeley-1973); StratumVariable=department; CausalRole=contested; IsConfounder=false; IsParadoxExplained=false; PerStratumWinner=none (mixed, not unanimous)', 'Does Berkeley show a clean reversal? No — PerStratumWinner=''none'' because the per-stratum winner is mixed (female wins 3/4 depts, male wins 1). The model surfaces a structural limit of the reversal definition: partial paradoxes are real but don''t satisfy the strict IsReversal criterion.', 'Witnessed: male pooled 52.8% vs female 39.9% (large gap). Per dept: female wins A (82%>62%), B (68%>63%), D (35%>33%); male wins C (37%>34%). No unanimous per-stratum winner → IsReversal=FALSE by strict definition. The intuitive paradox is real; the formal paradox is partial.', 'Add ParadoxStrength (scalar severity) to capture partial reversals — pooled gap and average per-stratum gap regardless of unanimity. Then StudySummary for epistemic coverage across all 3 studies.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-09', 'ParadoxStrength: scalar severity derived from pooled gap and per-stratum gap', 'complete', 'ParadoxStrength on TreatmentRankings; PooledGap and AvgStratumGap on StratumSummaries', 'How large is the reversal? Can we rank studies by paradox severity, and does strength correlate with allocation imbalance?', 'Kidney: pooled gap ~4.6pp favoring B, avg stratum gap ~5pp favoring A. Berkeley: larger pooled gap, varies by department. Balanced: strength=0 (no reversal).', 'StudySummary: roll up ReversalCount, ExplainedCount, AvgParadoxStrength across all studies. The model now describes its own epistemic coverage in a single view.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-10', 'StudySummary: the model witnesses its own epistemic coverage', 'complete', 'StudySummary table (one row per model instance): StudyCount, ReversalCount, ExplainedCount, UnexplainedCount, ImpossibleCount, AvgParadoxStrength', 'Across all studies in this model, what is the epistemic state? How many reversals, how many explained, how many witnessed-but-unexplained?', '3 studies: ReversalCount=2 (kidney+berkeley), ExplainedCount=1 (kidney), UnexplainedCount=1 (berkeley), ImpossibleCount=1 (balanced). The model now holds a mirror to itself.', 'Ask: how heavy is each stratum? Add StratumFraction to StratumSummaries — the fraction of the study''s total cases that land in each stratum. The weight each stratum carries IS the lever the confounder pulls.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-11', 'StratumFraction: the weight each stratum carries in the pooled average', 'complete', 'StratumFraction (and StudyTotalCases, StratumTotalCases) on StratumSummaries', 'What fraction of the study''s total cases land in each stratum? High StratumFraction on a low-success stratum pulls the pooled rate down — and when that stratum is also over-allocated to one treatment, the reversal follows.', 'kidney-1986: large-stratum = (263+80)/700 = 49%; small-stratum = (87+270)/700 = 51%. Nearly equal stratum weights — but unequal per-treatment allocation (75% of A is in large; 23% of B is in large). The weight alone is not the mechanism; the differential allocation into heavy strata is.', 'Add WeightedStratumRate: StratumFraction × StratumSuccessRate per treatment row. Sum these across strata to reconstruct PooledRate from first principles. The DAG now witnesses the mechanism equation: pooled rate = weighted average of stratum rates.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-12', 'WeightedPull: mechanism equation witnessed — pooled rate = weighted sum of stratum rates', 'complete', 'WeightedStratumRate on StratumSummaries; PooledRateFromWeightsA and PooledRateFromWeightsB on TreatmentRankings', 'Can the DAG reconstruct each treatment''s pooled rate purely from stratum weights × stratum rates? If PooledRateFromWeights = PooledRate, the mechanism equation is verified: Simpson''s Paradox is algebraically explained.', 'kidney-1986: PooledRateFromWeightsA=0.833, PooledRateFromWeightsB=0.779 (A looks better under equal study-level weights). But actual pooled rates are A=0.780, B=0.826 (B looks better). The divergence IS the mechanism: real pooled uses treatment-level allocation weights; the reconstruction uses study-level weights. The swap between the two orderings shows exactly how differential allocation flips the conclusion. balanced-synthetic: weights match exactly (equal allocation = no flip possible).', 'Add AllocationBias to StratumSummaries: the difference between TreatmentExposureFraction for A and B in each stratum. High bias toward the losing treatment in a low-success stratum IS the confounder''s fingerprint as a witnessed number.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-13', 'AllocationBias: the confounder''s fingerprint as a signed witnessed number', 'complete', 'AllocationBias on StratumSummaries (AllocationFractionA - AllocationFractionB); also AllocationFractionA, AllocationFractionB, TreatmentACasesHere, TreatmentBCasesHere, TreatmentATotalCases, TreatmentBTotalCases', 'In each stratum, is one treatment disproportionately concentrated here? AllocationBias = AllocationFractionA - AllocationFractionB: positive means A is over-represented here, negative means B is. A strong negative bias in a low-success stratum is the confounder''s fingerprint.', 'kidney-1986 large-stratum: AllocationFractionA=263/350=0.751, AllocationFractionB=80/350=0.229, AllocationBias=+0.523. A is massively over-allocated to the hard (large-stone) stratum. This single number summarizes why the pooled rate misleads: A carries 52pp more exposure to the hard case, dragging its pooled average down below B''s despite beating B in both strata.', 'Add a 4th study: kidney-balanced — same stratum rates as kidney-1986 but with equal allocation (50/50 split). AllocationBias=0 everywhere, IsReversal=FALSE. The counterfactual shows the reversal is purely an allocation artifact, not a property of the treatment rates themselves.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-14', 'Counterfactual: kidney-balanced isolates allocation as the sole cause of the reversal', 'complete', 'Fourth study (kidney-balanced): same stratum rates as kidney-1986, equal allocation (175 cases per cell). IsReversal=FALSE, AllocationBias=0, ParadoxStrength=0.', 'If the same doctors, same disease, same treatments, same stratum difficulty — but patients were allocated equally — would the paradox still exist? The DAG answers: no. The reversal lives in the allocation, not in the treatment rates.', 'kidney-balanced: PooledRateA = (163+128)/350 = 0.831, PooledRateB = (152+120)/350 = 0.777. A wins pooled AND per-stratum. IsReversal=FALSE, ParadoxStrength=0. AllocationBias=0 in both strata. The counterfactual witnesses that the reversal in kidney-1986 is entirely an artifact of differential allocation, not of treatment efficacy.', 'Add ReversalThreshold to TreatmentRankings: the minimum AllocationBias magnitude needed to flip the pooled winner. How far is kidney-1986 from the threshold? How close is berkeley-1973? This quantifies paradox fragility vs robustness.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-15', 'ReversalThreshold: how robust or fragile is each study''s paradox?', 'complete', 'MaxAllocationBias, WeightedStratumGapSum, ThresholdMargin on TreatmentRankings', 'How much allocation bias is needed to produce a reversal? Is the observed bias well above threshold (robust paradox) or barely over it (fragile paradox)? ThresholdMargin = observed bias minus minimum needed.', 'kidney-1986: ReversalIntensity=1.0, ThresholdMargin=+0.5 — maximally robust, every stratum opposes pooled. berkeley-1973: ReversalIntensity=0.75, ThresholdMargin=+0.25 — past threshold but not unanimous (3/4 departments oppose). balanced-synthetic and kidney-balanced: intensity=0, margin=-0.5 — structurally impossible. ThresholdMargin > 0 means the paradox is robust; < 0 means absent or impossible.', 'Pour a real-world dataset with a known mediator (not confounder) through the same DAG and witness where it lands on the reversal_intensity × paradox_strength plane. The geometry of the plane is the next frontier.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-16', 'StratumGap: per-stratum rate difference as a signed witnessed number', 'planned', 'StratumGap field on StratumSummaries (StratumRateA - StratumRateB, signed)', 'In each stratum, how large is the treatment advantage, and in which direction? StratumGap > 0 means A wins here; < 0 means B wins. Summing StratumGap × StratumFraction gives the equal-weight pooled gap — a new derived node.', 'kidney-1986: small-stratum gap = +0.064 (A wins by 6.4pp), large-stratum gap = +0.043 (A wins by 4.3pp). Both positive — A wins everywhere. The pooled gap is negative (B appears to win by 4.6pp) purely due to allocation. The signed gap makes this contradiction arithmetically visible in one column.', 'Derive WeightedStratumGapSum on TreatmentRankings: SUM(StratumGap × StratumFraction). This is the equal-weight pooled gap — the gap you would see if allocation were perfectly balanced. Compare it to the actual PooledGap to get a precise measure of how much the allocation is distorting the signal.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-17', 'WeightedStratumGapSum: the equal-weight signal vs the distorted pooled signal', 'planned', 'WeightedStratumGapSum on TreatmentRankings (SUM of StratumGap × StratumFraction); AllocationDistortion = PooledGap direction vs WeightedStratumGapSum direction', 'If allocation were equal, what would the pooled gap be? WeightedStratumGapSum answers this. When WeightedStratumGapSum and PooledGap have opposite signs, the allocation has not just shrunk the signal — it has flipped it. That sign flip IS Simpson''s Paradox, precisely.', 'kidney-1986: WeightedStratumGapSum = 0.051×0.49 + 0.064×0.51 ≈ +0.058 (A would win by 5.8pp under equal weights). Actual PooledGap direction: B wins. Sign flip confirmed. This is a more precise characterization than IsReversal: it handles partial flips and gives a magnitude to the distortion.', 'Add a real-world dataset with a mediator variable (e.g. a drug study where the mediating pathway is known) and witness whether it lands above or below threshold_margin=0 on the plane. The plane needs more empirical points to test whether it predicts anything.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-18', 'Real dataset: UCB law school admissions 1970s — mediator vs confounder test', 'planned', 'Fifth study with a known mediator structure; StratumVariable.CausalRole=''mediator''; new witnessed coordinates on the reversal_intensity × paradox_strength plane', 'Does a study with a mediator (not a confounder) still land past threshold_margin=0? If yes, the plane doesn''t distinguish causal structure from allocation structure. If no, the plane implicitly encodes causal information via the allocation pattern.', 'To be filled after dataset is sourced. Hypothesis: mediator studies land near the threshold with moderate intensity but lower paradox_strength than true confounders, because mediators create weaker allocation bias.', 'Add a ColliderStudy — a third causal structure where conditioning on the stratifying variable INTRODUCES bias rather than removing it. Collider bias is the inverse of confounding and should produce a distinctive signature on the plane.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-19', 'ColliderStudy: conditioning on a collider introduces bias — inverse signature on the plane', 'planned', 'Sixth study with CausalRole=''collider''; StratumVariable where conditioning worsens rather than corrects the estimate; new plane coordinates', 'When the stratifying variable is a collider, stratification makes the estimate worse, not better. Does the plane capture this? A collider study should produce IsReversal=TRUE on the stratified view but with the stratified conclusion being the wrong one — the opposite of what stratification usually achieves.', 'Synthetic collider dataset: two independent treatments, a common effect (the collider) used as the stratifying variable. Conditioning on the collider introduces a spurious association. The DAG should show this as a reversal in the wrong direction.', 'Add StratumVariable.BiasDirection field: ''corrects'' (confounder — stratification helps), ''worsens'' (collider — stratification hurts), ''neutral'' (no causal path through this variable). The plane then splits into two half-planes by bias direction.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-20', 'BiasDirection: does stratification help or hurt? The plane splits in two', 'planned', 'BiasDirection field on StratumVariables (''corrects''|''worsens''|''neutral''); IsStratificationRecommended derived boolean on TreatmentRankings', 'Given the causal structure of the stratifying variable, does stratifying on it move the estimate toward truth or away from it? This is the clinically actionable output: should a researcher stratify on this variable or not?', 'kidney-1986: BiasDirection=''corrects'' (stone_size is a true confounder; stratifying reveals A''s true advantage). collider-synthetic: BiasDirection=''worsens'' (stratifying on the collider creates a spurious reversal). IsStratificationRecommended = TRUE for confounders, FALSE for colliders.', 'Add a multi-confounder study: two stratifying variables, each a confounder, requiring nested stratification. The current DAG only handles one level of stratification. How does the plane behave when there are two simultaneous confounders?') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-21', 'Multi-confounder: nested stratification with two simultaneous confounders', 'planned', 'Seventh study with two StratumVariables both marked IsConfounder=TRUE; NestedStratumLabel combining both variables; new cells at the intersection', 'When two variables confound simultaneously, does stratifying on one reveal the other''s distortion? Can the DAG represent nested strata (e.g. small+young, small+old, large+young, large+old) and detect which confounder is doing more work?', 'Synthetic: stone_size AND patient_age both confound treatment assignment and outcome. 8 cells (2 strata × 2 age groups × 2 treatments). The paradox may appear at the pooled level, disappear at the stone_size level, and reappear at the age level — a double Simpson''s Paradox.', 'Add ConfoundingDepth to TreatmentRankings: how many levels of stratification are required before the reversal disappears? A study with ConfoundingDepth=1 is resolved by one stratification; depth=2 requires two. The plane gains a third dimension.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-22', 'ConfoundingDepth: how many stratification levels until the paradox resolves?', 'planned', 'ConfoundingDepth field on TreatmentRankings (integer: 0 = no paradox, 1 = one stratification resolves it, 2+ = deeper); derived from the nested stratum structure', 'Is this a shallow paradox (one confounder, one stratification) or a deep one (multiple confounders, requires nested stratification to resolve)? ConfoundingDepth is a new axis that the current plane does not capture.', 'kidney-1986: ConfoundingDepth=1 (stone_size alone resolves it). Multi-confounder synthetic: ConfoundingDepth=2. The plane becomes a volume: intensity × strength × depth. Studies that require deep stratification are the most dangerous in practice because the confounder is hardest to identify.', 'Source a real published dataset with a known double Simpson''s Paradox (they exist in epidemiology literature) and verify its ConfoundingDepth=2 coordinate against the DAG''s derivation.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-23', 'Real dataset: Freedman 1979 or equivalent — known double paradox, verify ConfoundingDepth=2', 'planned', 'Real-world double Simpson''s Paradox study; empirical verification of ConfoundingDepth=2 coordinate', 'Does a published double paradox land at ConfoundingDepth=2 as the DAG predicts? If yes, the model''s depth measure is empirically calibrated. If no, what does the DAG reveal about why the published analysis is incomplete?', 'To be filled after dataset is sourced. The key question: does the DAG surface a second reversal that the original paper missed, or does it confirm the paper''s finding? Either result is informative.', 'Add a time-varying confounder study: a confounder whose strength changes over time (e.g. a drug study where sicker patients are preferentially allocated to treatment A in early periods but not later). This requires a temporal dimension the current DAG doesn''t have.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-24', 'TemporalStrata: time period as a stratifying variable — does the paradox vary over time?', 'planned', 'TimePeriod field on CaseCells; TemporalStratumSummaries; time-varying AllocationBias — does the confounder''s strength increase or decrease over successive periods?', 'If a study spans multiple time periods, does the allocation bias (and therefore the paradox) strengthen or weaken over time? A time-varying confounder produces a paradox that appears, intensifies, then resolves — or vice versa. The DAG should witness the trajectory.', 'Synthetic: kidney-style study over 3 time periods. Early period: severe allocation bias (heavy confounding). Late period: randomized trial protocol introduced, bias near zero. StrengthOverTime = sequence of ParadoxStrength values. The paradox should decay as the allocation becomes more balanced.', 'Add StrengthTrend to TreatmentRankings: is the paradox growing or shrinking over time? A positive trend is a warning signal; a negative trend suggests an intervention is correcting the confounding.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-25', 'StrengthTrend: is the paradox intensifying or resolving over successive time periods?', 'planned', 'StrengthTrend on TreatmentRankings (computed across temporal strata); EarlyParadoxStrength, LateParadoxStrength, TrendDirection (''increasing''|''decreasing''|''stable'')', 'If a study''s paradox is getting stronger over time, is the confounder becoming more dominant? If it''s weakening, is something correcting the allocation bias? StrengthTrend converts the plane coordinate into a velocity — not just where the study is, but which direction it''s moving.', 'Synthetic temporal dataset: EarlyStrength=0.08, MidStrength=0.05, LateStrength=0.01. TrendDirection=''decreasing''. The DAG witnesses that the paradox is resolving as allocation becomes more balanced over time.', 'Add a meta-analysis study: aggregate data from multiple independent studies of the same treatment. Does pooling across studies (ignoring study-level heterogeneity) create a Simpson''s Paradox at the meta level? The study is now the stratum.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-26', 'Meta-analysis paradox: studies as strata — Simpson''s Paradox at the meta level', 'planned', 'MetaStudy entity where each component study is a stratum; the pooled meta-analysis rate vs the per-study rates; IsMetaReversal boolean', 'When multiple studies are pooled into a meta-analysis, can the pooled conclusion reverse the per-study conclusions? This is Simpson''s Paradox one level up: studies are the strata, and heterogeneity in study size/quality plays the role of the confounder.', 'Synthetic meta-analysis: 3 small studies all favor A (consistent), 1 large study favors B (overwhelming by weight). Pooled meta-analysis favors B. IsMetaReversal=TRUE. This is the structure of several controversial meta-analyses in the published literature.', 'Add StudyWeight (sample size fraction) and StudyQuality (risk-of-bias score) as stratifying variables on MetaStudy. Does quality-weighted pooling resolve the meta-reversal? The DAG should witness whether quality adjustment corrects the meta-level paradox.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-27', 'StudyQuality: does risk-of-bias weighting resolve the meta-level paradox?', 'planned', 'StudyQuality score on MetaStudy strata; QualityWeightedPooledRate; IsQualityAdjustedReversal — does the reversal survive quality weighting?', 'If the large study that dominates the meta-analysis has high risk of bias, and the small studies that all agree have low risk of bias, does quality-weighting flip the meta-level conclusion? The DAG should witness whether quality adjustment is sufficient to resolve the meta-reversal.', 'Synthetic: the one large pro-B study has RiskOfBias=high. Three small pro-A studies have RiskOfBias=low. QualityWeightedPooledRate favors A. IsQualityAdjustedReversal=FALSE. The meta-paradox resolves under quality weighting — witnessed as a derived fact.', 'Source a real controversial meta-analysis (e.g. antidepressant efficacy, low-fat diet) and compute its IsMetaReversal and IsQualityAdjustedReversal coordinates. This is the most direct path to a finding with clinical relevance.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-28', 'Real meta-analysis: antidepressant or dietary fat — does the DAG surface a meta-level reversal?', 'planned', 'Real-world meta-analysis study poured through the MetaStudy structure; empirical IsMetaReversal coordinate', 'Does the DAG identify a meta-level Simpson''s Paradox in a published meta-analysis? If yes, which stratum (study) is acting as the confounder, and what is its AllocationBias at the meta level?', 'To be filled after dataset is sourced. Candidate: Kirsch et al. 2008 antidepressant meta-analysis (large unpublished negative studies dominate when added). The DAG should witness whether publication bias is creating a meta-level allocation bias.', 'Add PublicationBias as a StratumVariable at the meta level: studies that were published only because they were positive are ''over-allocated'' to the positive side. This is the meta-level equivalent of treatment allocation bias in a clinical study.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-29', 'PublicationBias as meta-level AllocationBias: unpublished studies as the hidden stratum', 'planned', 'PublicationStatus field on MetaStudy strata (''published''|''unpublished''|''registered''); PublicationBias as a StratumVariable with CausalRole=''confounder'' at the meta level', 'If unpublished studies are added as a hidden stratum, does the meta-level AllocationBias change? The DAG should witness that publication bias is structurally identical to treatment allocation bias in a clinical study — it over-allocates the visible evidence to one conclusion.', 'Synthetic: 10 published studies (8 favor A, 2 favor B). 10 unpublished studies (2 favor A, 8 favor B). Published-only meta-analysis: IsMetaReversal=FALSE (A wins). Full meta-analysis including unpublished: IsMetaReversal=TRUE (B wins). PublicationBias IS the confounder.', 'Add a PolicyReversal field: does the clinical or policy recommendation change when the correct (stratified or quality-weighted) analysis is used instead of the naive pooled analysis? PolicyReversal=TRUE is the highest-stakes output of the entire DAG.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-30', 'PolicyReversal: does the correct analysis change the recommended action?', 'planned', 'PolicyReversal boolean on TreatmentRankings (TRUE when IsReversal=TRUE OR IsMetaReversal=TRUE AND the reversal changes the preferred treatment); PolicyReversalSeverity scalar', 'Of all the studies in the model, which ones would lead to a different clinical decision if analyzed correctly? PolicyReversal=TRUE is the operationally meaningful output — it identifies studies where the naive aggregate analysis causes actual harm.', 'kidney-1986: PolicyReversal=TRUE (naive analysis says use B; correct analysis says use A). kidney-balanced: PolicyReversal=FALSE (same conclusion either way). PublicationBias synthetic: PolicyReversal=TRUE (published literature recommends A; full evidence recommends B).', 'Add PolicyReversalSeverity: how many patients would receive the wrong treatment per 1000 cases if the naive analysis is used? This converts the abstract geometric coordinate into a human cost estimate — the most compelling output for a clinical audience.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-31', 'PolicyReversalSeverity: patients harmed per 1000 by using naive vs correct analysis', 'planned', 'PolicyReversalSeverity on TreatmentRankings: estimated excess failures per 1000 cases if naive pooled recommendation is followed instead of stratified recommendation', 'For each study where PolicyReversal=TRUE, how many patients per 1000 would have a worse outcome if the naive analysis drives the clinical decision? This is PooledGap × 1000, signed by PolicyReversal direction.', 'kidney-1986: PooledGap=0.046. If 1000 patients receive B (the naive recommendation) instead of A (the correct recommendation), approximately 46 additional failures occur. PolicyReversalSeverity=46 per 1000. This is the human cost of the Simpson''s Paradox in this study.', 'Add RobustnessToCorrectionCost: how expensive (in sample size or analytical effort) would it be to detect and correct this paradox? A paradox that requires 10,000 patients to stratify correctly is more dangerous than one detectable with 500. Cost × severity = risk.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-32', 'CorrectionCost: how hard is this paradox to detect and correct?', 'planned', 'CorrectionCost on TreatmentRankings: estimated minimum sample size per stratum needed to detect the reversal with 80% power; DetectionDifficulty scalar', 'Some paradoxes are easy to detect (large strata, obvious allocation imbalance) and some are nearly invisible (small strata, subtle bias). CorrectionCost estimates how large a study would need to be to reliably surface this reversal. High cost + high severity = high danger.', 'Synthetic: a paradox with AllocationBias=0.05 (subtle) and StratumGap=0.02 (small effect) requires very large samples to detect. CorrectionCost=HIGH. A paradox with AllocationBias=0.52 (kidney-1986) is detectable with modest samples. CorrectionCost=LOW. The plane now has a cost contour.', 'Combine PolicyReversalSeverity and CorrectionCost into a DangerScore: severity / correction_cost. High severity that is cheap to detect is less dangerous than moderate severity that requires enormous samples. DangerScore ranks studies by practical risk.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-33', 'DangerScore: severity / correction_cost — which paradoxes are most dangerous in practice?', 'planned', 'DangerScore on TreatmentRankings (PolicyReversalSeverity / CorrectionCost); DangerRank across all studies in the model', 'Which studies in the model pose the greatest practical risk? DangerScore ranks them: a study with high severity and low correction cost should be fixed immediately; one with low severity and high correction cost may be acceptable to leave unresolved.', 'Hypothetical ranking: PublicationBias synthetic (high severity, very high correction cost because unpublished studies are hard to find) scores highest. kidney-1986 (moderate severity, low correction cost — just stratify on stone size) scores lower. DangerScore operationalizes the plane as a triage tool.', 'Survey the published epidemiology and clinical trial literature for studies that have high reversal_intensity and high paradox_strength but have not been stratified. These are the undetected paradoxes. The DAG is now a screening instrument.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-34', 'Literature screen: which published studies are high-risk candidates for undetected Simpson''s Paradox?', 'planned', 'LiteratureCandidate studies sourced from published research with known allocation imbalance and unstratified pooled analysis; preliminary plane coordinates computed from published summary statistics', 'Can the plane coordinates (reversal_intensity × paradox_strength) be approximated from published summary statistics alone, without raw data? If yes, the DAG becomes a screening tool applicable to any published pooled analysis.', 'To be filled after literature survey. Candidates: cholesterol-lowering trials with age-stratified subgroups, COVID-19 vaccine trials with comorbidity strata, surgical outcome studies with severity stratification. Each gets preliminary plane coordinates from published summary tables.', 'Select the highest-scoring literature candidate and request the raw data (or simulate from published summary statistics) to compute exact plane coordinates. This is the first external validation of the DAG as a screening instrument.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-35', 'External validation: compute exact plane coordinates for a high-risk literature candidate', 'planned', 'First external validation study poured through the full DAG pipeline; comparison of screening estimate (from published summaries) vs exact coordinates (from raw data)', 'How close are the screening-estimated plane coordinates to the exact coordinates computed from raw data? If they agree within 10%, the summary-statistic screening method is validated. If they diverge, what additional information is needed?', 'To be filled after raw data is obtained. The key metric: does the screening correctly classify the study as above or below threshold_margin=0? Classification accuracy is the primary validation criterion.', 'Repeat external validation on 3-5 more literature candidates, building a validation set. Once the screening method is validated, publish the plane, the screening formula, and the instrument description.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-36', 'Validation set: 3-5 external studies confirm screening accuracy across diverse domains', 'planned', 'Validation set of 3-5 external studies; ScreeningAccuracy metric; domain coverage (medicine, economics, social science, education)', 'Does the screening method correctly classify above/below threshold across diverse domains and sample sizes? A validated multi-domain screening instrument is the primary deliverable of this entire project.', 'Target domains: (1) a medical RCT with severity stratification, (2) an economics study with income stratification, (3) an education study with socioeconomic stratification, (4) a social science study with demographic stratification. Cross-domain validation establishes the instrument''s generality.', 'Write up the instrument: the plane definition, the screening formula, the threshold_margin=0 boundary, the DangerScore ranking, and the validation results. This is the publishable finding.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-37', 'Instrument definition: the plane, the boundary, the screening formula, and the danger score', 'planned', 'Formal instrument specification derived from the DAG: (1) plane axes definition, (2) threshold_margin=0 boundary formula, (3) summary-statistic screening approximation, (4) DangerScore ranking formula, (5) validation criteria', 'Can the full instrument be specified precisely enough that another researcher could apply it to a new dataset without access to the DAG? The instrument specification is the distillation of all 37 loops into a usable tool.', 'Instrument components: Axis 1 = StrataWonByLoser/StratumCount. Axis 2 = |PooledGap| × Axis1. Boundary = Axis1 > 0.5. Screening formula = approximable from published subgroup summaries. DangerScore = PolicyReversalSeverity/CorrectionCost. Each component traceable to a specific DAG node.', 'Submit instrument for peer review or post as a preprint. The DAG and the rulebook are the supplementary materials — the full derivation chain from raw case counts to instrument specification is machine-verifiable.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-38', 'Preprint: the DAG-derived Simpson''s Paradox screening instrument', 'planned', 'Preprint manuscript with DAG as supplementary material; reviewable derivation chain from CaseCell raw inputs to DangerScore output', 'Is the instrument''s derivation chain convincing to a methodologically sophisticated reader who has not seen the DAG? The preprint tests whether the DAG''s outputs can be communicated without the DAG itself being understood.', 'Preprint sections: (1) Problem statement — binary IsReversal misclassifies Berkeley-type studies. (2) The plane — two continuous axes derived from case-cell data. (3) The threshold — threshold_margin=0 is the precise boundary. (4) Validation — N studies across M domains. (5) Screening formula — applicable to published summaries.', 'After preprint feedback, identify the weakest assumption in the instrument (most likely: the StratumFraction weight uses study-level denominators rather than treatment-level denominators for the threshold formula). Resolve it in a loop that introduces treatment-level stratum weights.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-39', 'TreatmentLevelStratumWeight: correct the threshold formula for non-symmetric allocation', 'planned', 'TreatmentLevelStratumWeight on StratumSummaries (StratumCases_T / TotalCases_T per treatment, not per study); RevisedThresholdMargin using treatment-level weights', 'The current threshold_margin uses study-level stratum fractions. But the pooled rate uses treatment-level weights. Is the threshold formula off by this discrepancy? The loop computes both and witnesses whether they give materially different threshold classifications.', 'kidney-1986: study-level small-stratum weight = 0.51; treatment-A small-stratum weight = 0.249; treatment-B small-stratum weight = 0.771. Large discrepancy. RevisedThresholdMargin should be computed from treatment-level weights to match the actual pooled rate formula. If it changes the classification of any study, the current threshold is wrong.', 'With the correct threshold formula, recompute plane coordinates for all studies in the model. If any study changes quadrant (above/below threshold), the corrected formula is the publishable refinement. If none change, the study-level approximation is confirmed as sufficient.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-40', 'Recomputed plane: do corrected treatment-level weights change any study''s quadrant?', 'planned', 'Revised plane coordinates for all studies using TreatmentLevelStratumWeight; QuadrantChange boolean per study', 'Under the corrected threshold formula, does any study change from above-threshold to below-threshold or vice versa? A quadrant change means the study-level approximation was not just imprecise but qualitatively wrong. No quadrant change confirms the approximation is sufficient for screening.', 'To be computed after loop-39. Hypothesis: no quadrant changes for the current four studies (kidney-1986 is so far above threshold that the approximation error doesn''t matter). Berkeley-1973 is the risk case — it''s closest to the boundary at 0.25 margin.', 'Close the loop: return to the original question (is the binary IsReversal definition correct?) with all evidence assembled. Propose a revised definition: IsReversal_v2 = threshold_margin > 0, replacing the unanimity criterion. Show that IsReversal_v2 correctly classifies Berkeley as a reversal.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

-- ----------------------------------------------------------------------------
-- Studies: Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.
-- ----------------------------------------------------------------------------
INSERT INTO studies (study_id, title, source, source_url)
VALUES ('kidney-1986', 'Kidney Stone Treatment Study (Charig et al. 1986)', 'Charig CR et al. Comparison of treatment of renal calculi by open surgery, percutaneous nephrolithotomy, and extracorporeal shockwave lithotripsy. Br Med J. 1986;292:879.', 'https://www.bmj.com/content/292/6524/879') ON CONFLICT (study_id) DO UPDATE SET title = EXCLUDED.title, source = EXCLUDED.source, source_url = EXCLUDED.source_url;

INSERT INTO studies (study_id, title, source, source_url)
VALUES ('balanced-synthetic', 'Balanced Synthetic Study (degenerate case — reversal structurally impossible)', 'Synthetic dataset constructed to demonstrate that perfectly balanced treatment allocation across strata algebraically prevents Simpson''s Paradox. Not based on real data.', '') ON CONFLICT (study_id) DO UPDATE SET title = EXCLUDED.title, source = EXCLUDED.source, source_url = EXCLUDED.source_url;

INSERT INTO studies (study_id, title, source, source_url)
VALUES ('kidney-balanced', 'Kidney Stone Counterfactual (balanced allocation — reversal algebraically impossible)', 'Synthetic dataset derived from Charig 1986 kidney stone rates but with equal treatment allocation across strata (175 cases per cell). Demonstrates that the reversal in the original study is purely an allocation artifact.', '') ON CONFLICT (study_id) DO UPDATE SET title = EXCLUDED.title, source = EXCLUDED.source, source_url = EXCLUDED.source_url;

INSERT INTO studies (study_id, title, source, source_url)
VALUES ('berkeley-1973', 'UC Berkeley Graduate Admissions (Bickel et al. 1975) — contested confounder', 'Bickel PJ, Hammel EA, O''Connell JW. Sex Bias in Graduate Admissions: Data from Berkeley. Science. 1975;187:398-404.', 'https://www.science.org/doi/10.1126/science.187.4175.398') ON CONFLICT (study_id) DO UPDATE SET title = EXCLUDED.title, source = EXCLUDED.source, source_url = EXCLUDED.source_url;

-- ----------------------------------------------------------------------------
-- Treatments: Table: Treatments — the interventions being compared within a study. Each treatment belongs to one study.
-- ----------------------------------------------------------------------------
INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('kidney-1986-A', 'kidney-1986', 'A', 'Open surgery / percutaneous nephrolithotomy (PCNL) — the more invasive procedure, used preferentially for large stones.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('kidney-1986-B', 'kidney-1986', 'B', 'Extracorporeal shock wave lithotripsy (ESWL) — the less invasive procedure, used more for small stones.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('kidney-balanced-A', 'kidney-balanced', 'A', 'Open surgery / PCNL — same per-stratum rates as kidney-1986 (small:93.1%, large:73.0%) but now allocated equally (50%) to each stratum. Counterfactual treatment A.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('kidney-balanced-B', 'kidney-balanced', 'B', 'ESWL — same per-stratum rates as kidney-1986 (small:86.7%, large:68.8%) but allocated equally (50%) to each stratum. Counterfactual treatment B.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('balanced-synthetic-A', 'balanced-synthetic', 'A', 'Synthetic treatment A — 60% success rate in both strata. Allocated equally (50%) to each stratum.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('balanced-synthetic-B', 'balanced-synthetic', 'B', 'Synthetic treatment B — 50% success rate in both strata. Allocated equally (50%) to each stratum.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('berkeley-1973-male', 'berkeley-1973', 'A', 'Male applicants (labeled A). Pooled admission rate appears higher than female.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('berkeley-1973-female', 'berkeley-1973', 'B', 'Female applicants (labeled B). Pooled admission rate appears lower, but per-department rates are equal or higher in most departments.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

-- ----------------------------------------------------------------------------
-- Strata: Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.
-- ----------------------------------------------------------------------------
INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-1986-small', 'kidney-1986', 'small', 'Patients with small kidney stones — easier to treat, higher baseline success rate regardless of treatment.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-1986-large', 'kidney-1986', 'large', 'Patients with large kidney stones — harder to treat, lower baseline success rate regardless of treatment. Preferentially assigned to Treatment A.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-balanced-small', 'kidney-balanced', 'small', 'Small kidney stones — same baseline rates as kidney-1986 small stratum but now receiving exactly 50% of each treatment''s cases. Counterfactual stratum.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-balanced-large', 'kidney-balanced', 'large', 'Large kidney stones — same baseline rates as kidney-1986 large stratum but now receiving exactly 50% of each treatment''s cases. Equal allocation prevents confounding.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
